/* ===== HOO living owl controller (vector) ===== */
(function(){
  function ready(cb){var n=0;var t=setInterval(function(){if(document.querySelector('.owl-svg')){clearInterval(t);cb();}else if(++n>250)clearInterval(t);},50);}
  function withGSAP(cb){if(window.gsap)return cb(window.gsap);var sc=document.createElement('script');sc.src='https://cdn.jsdelivr.net/npm/gsap@3.12.5/dist/gsap.min.js';sc.async=1;sc.onload=function(){cb(window.gsap||null);};sc.onerror=function(){cb(null);};document.head.appendChild(sc);}
  ready(function(){withGSAP(function(g){[].slice.call(document.querySelectorAll('.owl-svg')).forEach(function(svg){setup(svg,g);});});});
  function setup(svg,g){
    var pups=[].slice.call(svg.querySelectorAll('.owl-pup'));
    var lids=[].slice.call(svg.querySelectorAll('.owl-lid'));
    var wrap=svg.parentNode, aura=wrap&&wrap.querySelector('.owl-aura');
    var tgt={x:0,y:0},cur={x:0,y:0},idle=0,ph=0;
    function move(e){var p=(e.touches&&e.touches[0])?e.touches[0]:e;var r=svg.getBoundingClientRect();var cx=r.left+r.width/2,cy=r.top+r.height/2;tgt.x=Math.max(-1,Math.min(1,(p.clientX-cx)/(r.width*0.8)));tgt.y=Math.max(-1,Math.min(1,(p.clientY-cy)/(r.height*0.8)));idle=0;}
    window.addEventListener('mousemove',move,{passive:1});window.addEventListener('touchmove',move,{passive:1});
    var PX=7,PY=6;
    function frame(){idle++;var dx=tgt.x,dy=tgt.y;if(idle>80){ph+=0.012;dx=Math.sin(ph)*0.7;dy=Math.sin(ph*1.7)*0.4;}cur.x+=(dx-cur.x)*0.1;cur.y+=(dy-cur.y)*0.1;var tx=cur.x*PX,ty=cur.y*PY;if(g){pups.forEach(function(p){g.set(p,{x:tx,y:ty});});}else{pups.forEach(function(p){p.setAttribute('transform','translate('+tx+','+ty+')');});}}
    if(g){
      g.ticker.add(frame);
      g.fromTo(svg,{scale:.9,opacity:0},{scale:1,opacity:1,duration:.6,ease:'back.out(1.5)',transformOrigin:'50% 50%'});
      g.to(wrap,{scale:1.03,duration:2.6,ease:'sine.inOut',repeat:-1,yoyo:true,transformOrigin:'50% 50%'});
      if(aura)g.to(aura,{opacity:.3,scale:.9,duration:1.9,ease:'sine.inOut',repeat:-1,yoyo:true});
      (function blink(){g.timeline().to(lids,{y:74,duration:.08,ease:'power2.in'}).to(lids,{y:0,duration:.13,ease:'power3.out'});g.delayedCall(1.6+Math.random()*3,blink);})();
    } else {
      (function loop(){frame();requestAnimationFrame(loop);})();
      setInterval(function(){lids.forEach(function(l){l.setAttribute('transform','translate(0,74)');});setTimeout(function(){lids.forEach(function(l){l.setAttribute('transform','translate(0,0)');});},150);},2800);
    }
  }
})();
